using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalWordCount { get; set; }
    public int SummaryWordCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarization: scores sentences by word frequency and returns
/// the top-ranked ones in their original document order.
/// </summary>
public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","can","could","of","in","to","for","with",
        "on","at","by","from","as","into","about","between","through","during",
        "before","after","above","below","it","its","this","that","these",
        "those","i","you","he","she","we","they","me","him","her","us","them",
        "my","your","his","our","their","not","no","nor","so","if","then",
        "than","too","very","just","also","more","most","such","each","every",
        "all","any","both","few","some","many","much","own","same","other"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Count == 0)
            return string.Empty;

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);

        var scored = sentences
            .Select((s, idx) => (Sentence: s, Index: idx, Score: ScoreSentence(s, wordFrequencies)))
            .ToList();

        var topIndices = scored
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index)       // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", topIndices);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;
                freq.TryGetValue(word, out int count);
                freq[word] = count + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0) return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out int freq))
                score += freq;
        }
        return score / words.Length;
    }

    private static string[] GetWords(string text)
        => WordRegex().Matches(text).Select(m => m.Value).ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using System.Text.RegularExpressions;
using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public partial class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizer;

    public SummarizeController(IDocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts a document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = CountWords(request.DocumentText),
            SummaryWordCount = CountWords(summary)
        });
    }

    private static int CountWords(string text)
        => string.IsNullOrWhiteSpace(text) ? 0 : WordRegex().Matches(text).Count;

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

