using System.Text.RegularExpressions;
using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public partial class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizer;

    public SummarizeController(IDocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts a document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = CountWords(request.DocumentText),
            SummaryWordCount = CountWords(summary)
        });
    }

    private static int CountWords(string text)
        => string.IsNullOrWhiteSpace(text) ? 0 : WordRegex().Matches(text).Count;

    [GeneratedRegex(@"\w+")]
    private static partial Regex WordRegex();
}

